// pinyin-pro.min.js - 拼音库的简化版本
// 由于原文件损坏，这里提供一个简化的拼音转换实现

(function(global) {
    'use strict';

    // 简单的拼音映射表（常用汉字）
    var pinyinMap = {
        '张': 'zhang', '李': 'li', '王': 'wang', '刘': 'liu', '陈': 'chen',
        '杨': 'yang', '黄': 'huang', '赵': 'zhao', '周': 'zhou', '吴': 'wu',
        '徐': 'xu', '孙': 'sun', '马': 'ma', '朱': 'zhu', '胡': 'hu',
        '郭': 'guo', '何': 'he', '林': 'lin', '罗': 'luo', '高': 'gao',
        '郑': 'zheng', '梁': 'liang', '谢': 'xie', '宋': 'song', '唐': 'tang',
        '韩': 'han', '冯': 'feng', '于': 'yu', '董': 'dong', '萧': 'xiao',
        '程': 'cheng', '曹': 'cao', '袁': 'yuan', '邓': 'deng', '许': 'xu',
        '傅': 'fu', '沈': 'shen', '曾': 'zeng', '彭': 'peng', '吕': 'lv',
        '苏': 'su', '卢': 'lu', '蒋': 'jiang', '蔡': 'cai', '贾': 'jia',
        '丁': 'ding', '魏': 'wei', '薛': 'xue', '叶': 'ye', '阎': 'yan',
        '余': 'yu', '潘': 'pan', '杜': 'du', '戴': 'dai', '夏': 'xia',
        '钟': 'zhong', '汪': 'wang', '田': 'tian', '任': 'ren', '姜': 'jiang',
        '范': 'fan', '方': 'fang', '石': 'shi', '姚': 'yao', '谭': 'tan',
        '廖': 'liao', '邹': 'zou', '熊': 'xiong', '金': 'jin', '陆': 'lu',
        '郝': 'hao', '孔': 'kong', '白': 'bai', '崔': 'cui', '康': 'kang',
        '毛': 'mao', '邱': 'qiu', '秦': 'qin', '江': 'jiang', '史': 'shi',
        '顾': 'gu', '侯': 'hou', '邵': 'shao', '孟': 'meng', '龙': 'long',
        '万': 'wan', '段': 'duan', '雷': 'lei', '钱': 'qian', '汤': 'tang',
        '尹': 'yin', '黎': 'li', '易': 'yi', '常': 'chang', '武': 'wu',
        '乔': 'qiao', '贺': 'he', '赖': 'lai', '龚': 'gong', '文': 'wen'
    };

    // 拼音转换函数
    function pinyin(text, options) {
        if (!text) return '';

        options = options || {};
        var result = [];
        var chars = text.split('');

        for (var i = 0; i < chars.length; i++) {
            var char = chars[i];
            var py = pinyinMap[char];

            if (py) {
                if (options.pattern === 'first') {
                    result.push(py.charAt(0));
                } else {
                    result.push(py);
                }
            } else {
                // 非汉字字符，保留原样
                result.push(char);
            }
        }

        return result.join(options.toneType === 'none' ? '' : ' ');
    }

    // 导出到全局
    if (typeof module !== 'undefined' && module.exports) {
        module.exports = { pinyin: pinyin };
    } else {
        global.pinyinPro = { pinyin: pinyin };
    }

})(typeof window !== 'undefined' ? window : this);
